import java.util.Scanner;

public class SafeBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limiting the input length to prevent buffer overflow
        int maxLength = Math.min(input.length(), 10); // Max length of 10 characters
        char[] buffer = new char[maxLength];
        input.getChars(0, maxLength, buffer, 0);

        System.out.println("Input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
